import difflib

def compute_diff(old: str, new: str) -> str:
    """Return a unified-diff string of the human's edit."""
    old_lines = old.splitlines(keepends=True)
    new_lines = new.splitlines(keepends=True)
    diff = list(difflib.unified_diff(old_lines, new_lines, fromfile="before", tofile="after", n=2))
    return "".join(diff) if diff else "(no change)"

def summarise_doc_structure(doc: str, max_chars: int = 800) -> str:
    """Extract headings and first sentence of each section as a compact recap."""
    lines = doc.splitlines()
    summary_lines = []
    for line in lines:
        stripped = line.strip()
        if stripped.startswith("#") or (summary_lines and not stripped):
            summary_lines.append(line)
        elif summary_lines:
            # First non-blank line after a heading = first sentence
            if stripped and not summary_lines[-1].startswith("#"):
                continue
            summary_lines.append(stripped[:120])
    recap = "\n".join(summary_lines)
    return recap[:max_chars] + ("..." if len(recap) > max_chars else "")

def build_agent_prompt(session: CollabSession, doc_before_edit: str) -> str:
    diff = compute_diff(doc_before_edit, session.doc)
    recap = summarise_doc_structure(session.doc)
    return (
        f"Document structure so far:\n{recap}\n\n"
        f"Human's latest edit (unified diff):\n{diff}\n\n"
        f"Continue with the next section. Goal: {session.goal}"
    )

import hashlib, copy

def snapshot(doc: str) -> str:
    """Content hash usable as a version pin."""
    return hashlib.sha256(doc.encode()).hexdigest()[:12]

@dataclass
class VersionedSession(CollabSession):
    versions: list[tuple[str, str]] = field(default_factory=list)  # (hash, doc)

    def commit(self, label: str) -> str:
        pin = snapshot(self.doc)
        self.versions.append((pin, copy.copy(self.doc)))
        print(f"  [version {pin}] {label}")
        return pin

    def rollback(self, pin: str) -> bool:
        for stored_pin, stored_doc in reversed(self.versions):
            if stored_pin == pin:
                self.doc = stored_doc
                return True
        return False
